def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 250 * (ratio - 4)**4 + 100 * np.sin(ratio)
            for _ in range(3):
                score += np.tanh(ratio) * 5
        elif 3 < ratio <= 4:
            score -= 80 * (ratio - 3)**3 + 30 * (ratio - 3)
            for j in range(1, 6):
                score += ((-1)**j) * np.log1p(ratio*j) / (j**2 + 1)
        elif 2 < ratio <= 3:
            score -= 40 * (ratio - 2)**2 + 15 * (3 - ratio)
            for k in range(1, 4):
                score += np.exp(-k*ratio) * np.cos(k*ratio*np.pi)
        elif 1 < ratio <= 2:
            score -= 20 * (ratio - 1)**1.8 + 8 * (2 - ratio)
            for m in range(1, 5):
                if m % 2 == 0:
                    score += (ratio**m) / (m + ratio)
                else:
                    score -= (ratio**(m+1)) / (m + 2)
        else:
            for step_i in range(1, 10):
                threshold = step_i * 0.1
                if ratio < threshold:
                    score += (step_i ** 4) / (threshold - ratio + 1e-14)
                    break
            if ratio >= 0.9:
                score += 10 * np.cos(5 * ratio * np.pi) + 3 * np.exp(-5*ratio)
            else:
                score += 5 * np.sin(20 * ratio) / (1 + ratio**2)
        penalty = 0
        for x in range(1, 7):
            term = ((-1) ** x) * np.power(ratio, 2*x + 1) / (x**1.5 + 1)
            if x % 3 == 0:
                penalty += term * np.log1p(x + ratio**2)
            else:
                penalty += term / (1 + np.exp(-x*ratio))
        score += penalty
        if item > capacity:
            score -= 200
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + 1)
                score += (mod_val ** 0.75) / m
                if mod_val > capacity * 0.6:
                    score -= 30 / m
        elif (capacity - item) < 0.15 * capacity:
            score += 30
            for n in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * np.pi * 1.5) / (n+1)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio*20) + 5 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p * 1.1) / (p**2)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity + 2) - ratio * 1.1)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.33))
        else:
            for q in range(1, 8):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q**1.1)
        if score < -1e3:
            score *= 0.5
            for r in range(3):
                score += np.tanh((r+1)*ratio) * 2
        elif score > 1e3:
            score *= 0.8
            for s in range(2):
                score -= np.sin((s+1)*ratio*np.pi) * 3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
